const { PrismaClient } = require('@prisma/client');
const fs = require('fs');
const path = require('path');

const prisma = new PrismaClient();

async function main() {
  try {
    // Read all entries from _PostToTag
    const relations = await prisma.$queryRaw`SELECT * FROM "_PostToTag"`;
    console.log(`Found ${relations.length} relations in _PostToTag`);

    let migratedCount = 0;
    for (const rel of relations) {
      // A is Post, B is Tag
      await prisma.postTag.create({
        data: {
          postId: rel.A,
          tagId: rel.B,
        },
      });
      migratedCount++;
    }

    const result = { migratedCount };
    fs.writeFileSync(
      path.join(__dirname, 'm2m_migrate_result.json'),
      JSON.stringify(result, null, 2)
    );
    console.log(`Successfully migrated ${migratedCount} records.`);
  } catch (error) {
    console.error('Migration failed:', error);
    process.exit(1);
  } finally {
    await prisma.$disconnect();
  }
}

main();

